#include <iostream>
#include <limits>
#include <string>

class Calculator {
public:
    int add(int a, int b) { return a + b; }
    double add(double a, double b) { return a + b; }
    int add(int a, int b, int c) { return a + b + c; }
};

int main() {
    Calculator calc;
    std::cout << calc.add(5, 3) << std::endl;
    std::cout << calc.add(-10, 7) << std::endl;
    std::cout << calc.add(std::numeric_limits<int>::max(), 1) << std::endl;
    std::cout << calc.add(std::numeric_limits<int>::min(), -1) << std::endl;
    std::cout << calc.add(5.5, 3.2) << std::endl;
    std::cout << calc.add(-10.1, 7.5) << std::endl;
    std::cout << calc.add(123456789.123, 987654321.987) << std::endl;
    std::cout << calc.add(1, 2, 3) << std::endl;
    std::cout << calc.add(-1, -2, -3) << std::endl;
    std::cout << calc.add(std::numeric_limits<int>::max() - 1, 1, 1) << std::endl;
    return 0;
}
